### Step 4: Implement Game Over Detection
Here's how you can implement the game over detection logic:

```python
class Board:
    # ... (previous code)

    def is_game_over(self):
        black_pieces = [x for row in self.board for x in row if x and x.color == 'B']
        white_pieces = [x for row in self.board for x in row if x and x.color == 'W']

        if not black_pieces:
            return True, "White wins"
        elif not white_pieces:
            return True, "Black wins"

        # Check for stalemate
        for piece in black_pieces + white_pieces:
            if self.get_valid_moves(piece) != []:
                return False

        return True, "Draw"

    def get_valid_moves(self, piece):
        moves = []
        x, y = self.find_piece_location(piece)

        # Normal moves
        for dx, dy in [(1, 1), (1, -1), (-1, 1), (-1, -1)]:
            new_x, new_y = x + dx, y + dy
            if 0 <= new_x < 8 and 0 <= new_y < 8 and self.board[new_x][new_y] is None:
                moves.append(((x, y), (new_x, new_y)))

        # Capture moves
        for dx, dy in [(2, 2), (2, -2), (-2, 2), (-2, -2)]:
            capture_x, capture_y = x + dx // 2, y + dy // 2
            if 0 <= capture_x < 8 and 0 <= capture_y < 8:
                capture_piece = self.board[capture_x][capture_y]
                if capture_piece is not None and capture_piece.color != piece.color:
                    new_x, new_y = x + dx, y + dy
                    if 0 <= new_x < 8 and 0 <= new_y < 8 and self.board[new_x][new_y] is None:
                        moves.append(((x, y), (new_x, new_y)))

        return moves

    def find_piece_location(self, piece):
        for i in range(8):
            for j in range(8):
                if self.board[i][j] == piece:
                    return i, j
